import React, { useState } from 'react';
import { InputNumber } from '..';
import { Space, Switch, Divider, Tooltip, Button, Input, Form, Slider } from '../..';
import './index.less';

export default {
  title: 'Components/InputNumber/临时示例',
  component: InputNumber,
};

function onChange(value?: number) {
  console.log('changed', value, typeof value);
}

function onPressEnter(event: React.KeyboardEvent<HTMLInputElement>) {
  console.log('onPressEnter', event);
}

export const Controlled = () => {
  const [value, setValue] = useState<number>();
  const onChangeFn = (v: any) => {
    console.log('onChange', v);
    setValue(v);
  };
  return (
    <InputNumber
      step={0.2}
      precision={1}
      max={10.1}
      min={0}
      placeholder="请输入"
      value={value}
      // formatter={v => `${v}%`}
      // parser={v => (v ? v.replace('%', '') : '')}
      onChange={onChangeFn}
    />
  );
};

