export const Error = () => {
  const [error1, setError1] = React.useState(false);
  const internalOnChange = (value: any) => console.log('changed', value);
  const [val1, setVal1] = React.useState<any>(1);
  const oRef1 = React.useRef<HTMLInputElement>(null);
  return (
    <>
      <Space size="large" direction="vertical">
        <div>
          <span>受控的 error: &nbsp;&nbsp;</span>
          <InputNumber error={error1} placeholder="请输入" onChange={internalOnChange} />
          &nbsp;&nbsp;
          <Button onClick={() => setError1(!error1)}>点我切换 error</Button>
        </div>
        --------------------------------------------------------
        <div>
          <span>自动把输入的字符过滤, 只保留数字: &nbsp;&nbsp;</span>
          <InputNumber onlyNumber value={val1} placeholder="请输入" onChange={(e: any) => setVal1(e)} />
          <br />
          <br />
          <Input ref={oRef1} placeholder="输入数字或字符, 然后点击下头按钮" style={{ width: 300 }} />
          <br />
          <br />
          <Button onClick={() => setVal1(oRef1.current?.value)}>先输入, 再点击, 然后改变</Button>
        </div>
        --------------------------------------------------------
        <div>
          <span>键入字符时自动报错: &nbsp;&nbsp;</span>
          <InputNumber min={-10} max={10} placeholder="请输入" onChange={internalOnChange} />
        </div>
        --------------------------------------------------------
        <div>
          <span>支持科学记数法: &nbsp;&nbsp;</span>
          <InputNumber placeholder="请输入" onChange={internalOnChange} />
        </div>
      </Space>
    </>
  );
};

export const Inform = () => (
  <Form layout="horizontal" initialValues={{ username: '', password: '', remember: true }}>
    <Form.Item
      required
      label="Username"
      name="username"
      rules={[{ required: true, message: 'Please input your username!' }]}
    >
      <InputNumber
        formatter={value => `$ ${value}`.replace(/\B(?=(\d{3})+(?!\d))/g, ',')}
        parser={value => value?.replace(/\$\s?|(,*)/g, '') || ''}
        precision={2}
      />
    </Form.Item>
  </Form>
);

export const LongWidth = () => {
  const [width, setWidth] = useState(0);
  const [value, setValue] = useState<number | undefined>(999);
  const onSliderChange = (v: React.SetStateAction<number>) => {
    setWidth(v);
  };
  return (
    <>
      <Space direction="vertical" size="large">
        <InputNumber
          value={value}
          formatter={e => `okokokokokokokokokokokokokok${e}okokokokokokokokokokokokokok`}
          style={{ width }}
        />
        <InputNumber
          value={value}
          formatter={e => `okokokokokokokokokokokokokok${e}okokokokokokokokokokokokokok`}
          style={{ width: 100 }}
        />
        <InputNumber
          value={value}
          formatter={e => `okokokokokokokokokokokokokok${e}okokokokokokokokokokokokokok`}
          style={{ width: 200 }}
        />
        <InputNumber
          value={value}
          formatter={e => `okokokokokokokokokokokokokok${e}okokokokokokokokokokokokokok`}
          style={{ width: 300 }}
        />
        <div />
        <Space>
          <InputNumber
            style={{ width: 300 }}
            onChange={e => {
              console.log(e);
              e ? setValue(e || 0) : setValue(undefined);
            }}
          />
          <span>输入</span>
        </Space>
        <Slider
          style={{
            width: 400,
          }}
          min={30}
          max={500}
          defaultValue={30}
          onChange={onSliderChange}
        />
      </Space>
    </>
  );
};

export const FormatterWithPrecision = () => {
  const [v, setV] = React.useState<number | undefined>();
  const onChangeHandler = (changed: number | undefined) => {
    setV(changed);
    console.log('onChange Triggered: ', changed);
  };
  return (
    <>
      <h4> Formatter / Precision / Max</h4>
      <p>Formatter 需要实时生效， precison/ max 只有 blur 或者 step 时才能生效</p>
      <p> 受控：</p>
      <InputNumber
        value={v}
        formatter={value => `$ ${value}`.replace(/\B(?=(\d{3})+(?!\d))/g, ',')}
        parser={value => value?.replace(/\$\s?|(,*)/g, '') || ''}
        onChange={onChangeHandler}
        precision={2}
        max={100}
      />
      <p> 非受控：</p>
      <InputNumber
        formatter={value => `$ ${value}`.replace(/\B(?=(\d{3})+(?!\d))/g, ',')}
        parser={value => value?.replace(/\$\s?|(,*)/g, '') || ''}
        onChange={changed => console.log('onChange Triggered: ', changed)}
        precision={2}
        max={100}
      />
      <InputNumber
        value={v}
        onChange={onChangeHandler}
        formatter={value => (Number(value) * 100).toString()}
        parser={value => String(Number(value) / 100)}
        precision={4}
        max={1}
        min={0}
        onlyNumber
        step={0.0001}
      />
    </>
  );
};
